package work

import (
	"context"
	"errors"
	"fmt"
	"io"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/trackerpaths"
)

// DefaultPreClaimTimeout bounds pre-claim readiness hooks when callers do not
// provide an explicit timeout.
const DefaultPreClaimTimeout = 5 * time.Minute

const SystemicPreClaimReasonPrefix = "systemic_preclaim:"

// TrackerContentionPreClaimReasonPrefix marks a pre-claim skip caused by
// transient multi-worker contention on DDx-managed tracker/metadata files
// (.ddx/beads.jsonl, .ddx/metrics/attempts.jsonl, …) rather than a systemic
// repo-config problem. Like systemic skips it idles without cooldowning the
// bead, but it carries a distinct reason code so operators can tell transient
// contention apart from a configuration wedge (ddx-df77e668).
const TrackerContentionPreClaimReasonPrefix = "tracker_contention_preclaim:"

// preClaimClass categorizes a pre-claim hook error so the guard can choose
// between idling without cooldown (systemic / tracker-contention) and the
// per-bead two-strikes cooldown policy (bead-specific failures).
type preClaimClass int

const (
	preClaimClassBeadSpecific preClaimClass = iota
	preClaimClassSystemic
	preClaimClassTrackerContention
)

// Guard decides whether a bead may proceed. Callers use the returned reason
// for skip telemetry and logs.
type Guard interface {
	Allow(ctx context.Context, beadID string) (bool, string)
}

// cooldownStore is the minimal store surface PreClaimGuard needs.
type cooldownStore interface {
	SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error
}

// PreClaimHook matches the work pre-claim hook signature.
type PreClaimHook func(ctx context.Context) error

// PreClaimGuard implements the two-strikes pre-claim policy. The first hook
// failure skips the candidate and retries it on the next presentation; the
// second failure parks the bead on execution cooldown.
type PreClaimGuard struct {
	hook     PreClaimHook
	store    cooldownStore
	log      io.Writer
	now      func() time.Time
	cooldown time.Duration
	timeout  time.Duration

	mu             sync.Mutex
	failCounts     map[string]int
	loggedSystemic map[string]bool
}

// NewPreClaimGuard constructs a Guard that owns the pre-claim hook retry
// state for one worker run.
func NewPreClaimGuard(hook PreClaimHook, store cooldownStore, log io.Writer, now func() time.Time, cooldown, timeout time.Duration) *PreClaimGuard {
	if now == nil {
		now = time.Now
	}
	if cooldown <= 0 {
		cooldown = 30 * time.Second
	}
	if timeout <= 0 {
		timeout = DefaultPreClaimTimeout
	}
	return &PreClaimGuard{
		hook:           hook,
		store:          store,
		log:            log,
		now:            now,
		cooldown:       cooldown,
		timeout:        timeout,
		failCounts:     make(map[string]int),
		loggedSystemic: make(map[string]bool),
	}
}

// Allow runs the pre-claim hook and applies the two-strikes retry policy.
func (g *PreClaimGuard) Allow(ctx context.Context, beadID string) (bool, string) {
	if g == nil || g.hook == nil {
		return true, ""
	}
	err, timedOut := callPreClaimHookWithTimeout(ctx, g.hook, g.timeout)
	if err != nil || timedOut {
		switch classifyPreClaimError(err) {
		case preClaimClassTrackerContention:
			reason := err.Error()
			g.mu.Lock()
			shouldLog := !g.loggedSystemic[reason]
			g.loggedSystemic[reason] = true
			g.mu.Unlock()
			if shouldLog && g.log != nil {
				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (transient tracker-file contention; leaving beads untouched)\n", err)
			}
			return false, TrackerContentionPreClaimReasonPrefix + reason
		case preClaimClassSystemic:
			reason := err.Error()
			g.mu.Lock()
			shouldLog := !g.loggedSystemic[reason]
			g.loggedSystemic[reason] = true
			g.mu.Unlock()
			if shouldLog && g.log != nil {
				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (systemic; leaving beads untouched)\n", err)
			}
			return false, SystemicPreClaimReasonPrefix + reason
		}

		g.mu.Lock()
		defer g.mu.Unlock()

		g.failCounts[beadID]++
		if g.failCounts[beadID] >= 2 {
			if g.store != nil {
				until := g.now().UTC().Add(g.cooldown)
				detail := "pre-claim hook failed"
				if err != nil {
					detail = err.Error()
				} else if timedOut {
					detail = fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
				}
				_ = g.store.SetExecutionCooldown(beadID, until, "preclaim-hook-failed", detail, "")
			}
		}
		if g.log != nil {
			switch {
			case timedOut:
				_, _ = fmt.Fprintf(g.log, "pre-claim hook timed out after %s (skipping %s)\n", g.timeout, beadID)
			case err != nil:
				_, _ = fmt.Fprintf(g.log, "pre-claim hook: %v (skipping %s)\n", err, beadID)
			}
		}
		if timedOut {
			return false, fmt.Sprintf("pre-claim hook timed out after %s", g.timeout)
		}
		return false, err.Error()
	}

	g.mu.Lock()
	delete(g.failCounts, beadID)
	g.mu.Unlock()
	return true, ""
}

func IsSystemicPreClaimSkipReason(reason string) bool {
	return strings.HasPrefix(reason, SystemicPreClaimReasonPrefix)
}

func SystemicPreClaimDetail(reason string) string {
	return strings.TrimPrefix(reason, SystemicPreClaimReasonPrefix)
}

func IsTrackerContentionPreClaimSkipReason(reason string) bool {
	return strings.HasPrefix(reason, TrackerContentionPreClaimReasonPrefix)
}

// IsManagedTrackerPath reports whether path is one of the DDx-managed tracker
// or durable-audit files that workers rewrite continuously.
func IsManagedTrackerPath(path string) bool {
	return trackerpaths.IsManagedTrackerPath(path)
}

func TrackerContentionPreClaimDetail(reason string) string {
	return strings.TrimPrefix(reason, TrackerContentionPreClaimReasonPrefix)
}

// classifyPreClaimError categorizes a pre-claim hook error. Systemic and
// tracker-contention classes both idle the worker without cooldowning the bead
// (no bead is at fault); they differ only in the reason code surfaced to
// operators. Anything else is treated as bead-specific and runs through the
// two-strikes cooldown policy.
func classifyPreClaimError(err error) preClaimClass {
	if err == nil {
		return preClaimClassBeadSpecific
	}
	msg := err.Error()
	// Staged tracker-file contention: a landing-worktree "staged changes" error
	// whose staged paths are exclusively DDx-managed tracker/metadata files.
	// Another worker's tracker commit is partially staged; the index settles
	// within milliseconds. Treating this as bead-specific would wrongly cooldown
	// beads during a transient multi-worker commit race (ddx-df77e668).
	if isStagedTrackerContentionError(msg) {
		return preClaimClassTrackerContention
	}
	// Branch divergence: local tracker has diverged from origin.
	if strings.Contains(msg, "local branch ") && strings.Contains(msg, " has diverged from origin ") {
		return preClaimClassSystemic
	}
	// Staged changes that include code/doc/test files: real work was never
	// committed. This is a systemic repo state, not a transient contention.
	if strings.Contains(msg, "staged changes") {
		return preClaimClassSystemic
	}
	// Git index.lock: an external git process holds the index lock. This is
	// transient (sub-second for normal operations); no bead is at fault.
	if strings.Contains(msg, "index.lock") {
		return preClaimClassSystemic
	}
	// Corrupt landing indexes are repo-health failures, not bead-specific
	// failures. Surface once as systemic so the worker can auto-repair or ask
	// for operator intervention without cooldowning beads.
	if strings.Contains(msg, "index file smaller than expected") ||
		strings.Contains(msg, "repairing landing worktree index") {
		return preClaimClassSystemic
	}
	return preClaimClassBeadSpecific
}

// isStagedTrackerContentionError reports whether a "landing worktree has staged
// changes" error lists only DDx-managed tracker/metadata files. A mixed or
// code-only staged set is NOT tracker contention (it is systemic).
func isStagedTrackerContentionError(msg string) bool {
	if !strings.Contains(msg, "staged changes after waiting") {
		return false
	}
	paths := stagedPathsFromError(msg)
	if len(paths) == 0 {
		return false
	}
	for _, p := range paths {
		if !isTrackerMetadataPath(p) {
			return false
		}
	}
	return true
}

// stagedPathsFromError extracts the repo-relative paths from the
// "landing worktree has staged changes after waiting <d>:\n<status>\t<path>"
// error body. Each path line is "<status><TAB><path>" (git diff --name-status);
// the leading summary line (before the first newline) is skipped.
func stagedPathsFromError(msg string) []string {
	lines := strings.Split(msg, "\n")
	if len(lines) <= 1 {
		return nil
	}
	var paths []string
	for _, line := range lines[1:] {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		if tab := strings.IndexByte(line, '\t'); tab >= 0 {
			line = line[tab+1:]
		}

// DefaultServerFailureWindow is the lookback window used to classify repeated
// no_viable_provider outcomes as a worker-level server outage.
const DefaultServerFailureWindow = 10 * time.Minute

// DefaultServerFailureThreshold is the number of distinct beads that must hit
// no_viable_provider inside the lookback window before the worker enters
// server-unavailable mode.
const DefaultServerFailureThreshold = 3

// DefaultServerHealthProbeInterval is the cadence used while the worker is in
// server-unavailable mode.
const DefaultServerHealthProbeInterval = 30 * time.Second

func (r ExecuteBeadLoopRuntime) effectiveServerFailureWindow() time.Duration {
	if r.ServerFailureWindow > 0 {
		return r.ServerFailureWindow
	}
	return DefaultServerFailureWindow
}

func (r ExecuteBeadLoopRuntime) effectiveServerFailureThreshold() int {
	if r.ServerFailureThreshold > 0 {
		return r.ServerFailureThreshold
	}
	return DefaultServerFailureThreshold
}

func (r ExecuteBeadLoopRuntime) effectiveServerHealthProbeInterval() time.Duration {
	if r.ServerHealthProbeInterval > 0 {
		return r.ServerHealthProbeInterval
	}
	return DefaultServerHealthProbeInterval
}

// DefaultPreClaimWarnRepeatThreshold is the number of consecutive identical
// pre-claim warn fingerprints across distinct bead IDs required to trip the
// operator-attention guard.
const DefaultPreClaimWarnRepeatThreshold = 5

// effectivePreClaimWarnRepeatThreshold returns the configured pre-claim warn
// repeat threshold, falling back to DefaultPreClaimWarnRepeatThreshold when
// unset.
func (r ExecuteBeadLoopRuntime) effectivePreClaimWarnRepeatThreshold() int {
	if r.PreClaimWarnRepeatThreshold > 0 {
		return r.PreClaimWarnRepeatThreshold
	}
	return DefaultPreClaimWarnRepeatThreshold
}

// DefaultReviewMaxRetries is the number of reviewer attempts allowed per
// committed result_rev before the loop emits a terminal
// `review-manual-required` event and stops re-executing primary. FEAT-022 §14.
const DefaultReviewMaxRetries = 3

// ReviewerSkippedEmptyDiffEventKind is the event kind emitted when the
// reviewer dispatch is skipped because the implementer produced no commits
// (BaseRev == ResultRev). Per ADR-024 P1: cheapest first — paying a reviewer
// to evaluate an empty diff is unjustified cost.
const ReviewerSkippedEmptyDiffEventKind = "reviewer-skipped-empty-diff"

// MaxLoopCooldown is the absolute upper bound the work will set for
// any work-retry-after value. Year-scale parks effectively mean
// "never retry" and that should be a deliberate operator choice via
// `ddx bead update --set work-retry-after=...`, not an automatic
// loop decision. Beyond this cap, the loop refuses to lengthen the cooldown
// further; an operator extending it manually still works.
const MaxLoopCooldown = 24 * time.Hour

// LandConflictCooldown is the short cooldown applied when all conflict-recovery
// paths fail (3-way ort auto-merge + optional focused-resolve agent) and the
// bead is parked as land_conflict_unresolvable. Much shorter than
// MaxLoopCooldown because land conflicts often resolve quickly as sibling beads
// advance the base branch.
const LandConflictCooldown = 15 * time.Minute

// StoreErrorCooldown is the short cooldown applied when a Store.* operation in
// the outcome-handling block returns a transient error. It prevents an
// immediate re-queue of the affected bead while allowing the loop to continue
// to the next candidate. Store errors during outcome handling are non-fatal:
// they are logged and emitted as loop-error events but do not terminate the
// worker.
const StoreErrorCooldown = 5 * time.Minute

// ProviderUnavailableCooldown is the retry pause for route/provider outages
// where no configured powerClass can currently run the bead. This is transient
// scheduler state, not bead quality evidence, so it must not become a durable
// triage:needs-investigation park.
const ProviderUnavailableCooldown = 15 * time.Minute

// SmartRetryCooldown is the queue-fairness pause after a real no_changes
// implementation attempt asks for status=open/smart retry. The bead remains
// open with transient smart-retry metadata, but a watch worker moves on instead
// of repeating the same empty-diff attempt every idle cycle.
const SmartRetryCooldown = 5 * time.Minute

// PausedInfraInterval is the polling interval the worker waits in paused-infra
// state before re-evaluating the queue. Infra failures (no_viable_provider,
// provider_connectivity) transition the worker to this state instead of parking
// individual beads: beads remain immediately reclaimable, and the worker retries
// after this window.
const PausedInfraInterval = 2 * time.Minute

// SubmitWithPreMergeChecks is the canonical land-back step for the execute-bead
// loop. It runs the project's .ddx/checks/*.yaml gate against the worker's
// (baseRev, resultRev) before forwarding to submit. On Blocked, it preserves
// the worker's result under refs/ddx/iterations/, records checks-blocked
// events on the bead, and returns the synthesised LandResult{Status:"preserved"}
// without ever calling submit. On pass, honoured checks-bypass annotations are
// recorded as checks-bypass events and submit runs normally.
//
// submit is the project's land coordinator entry point (typically
// LocalLandCoordinator.Submit or the server-side coordinator submit).
//
// The implementation lives in checks_premerge.go alongside its supporting
// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
// loop's land-back call site is one obvious helper rather than three nested
// ones, and so callers wiring the gate do not need to import the helper layer
// directly.
func SubmitWithPreMergeChecks(
	ctx context.Context,
	projectRoot string,
	b *bead.Bead,
	res *ExecuteBeadResult,
	submit func(LandRequest) (*LandResult, error),
	eventStore BeadEventAppender,
	actor, source string,
	now func() time.Time,
) (*LandResult, *PreMergeChecksOutcome, error) {
	if now == nil {
		now = time.Now
	}
	if submit == nil {
		return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
	}
	evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
	outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
	if err != nil {
		// Treat checks_bypass / loader errors as a hard preserve: the worker
		// did its job; the operator misconfigured the gate. Better to park
		// the result under an iteration ref than to silently land it.
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if upErr := (&RealGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
			return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
		}
		return &LandResult{
			Status:      "preserved",
			PreserveRef: ref,
			Reason:      "pre-merge checks setup error: " + err.Error(),
		}, nil, nil
	}
	if outcome.Blocked {
		land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealGitOps{})
		if perr != nil {
			return nil, outcome, perr
		}
		if eventStore != nil {
			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
		}
		return land, outcome, nil

				Detail:  "shared readiness schema mismatch",
