	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-a")
		_, _ = workerA.Run(context.Background(), rcfg, rt)
	}()
	go func() {
		defer wg.Done()
		rcfg, rt := makeRuntime("worker-b")
		_, _ = workerB.Run(context.Background(), rcfg, rt)
	}()

	select {
	case <-lintStarted:
	case <-time.After(5 * time.Second):
		t.Fatal("lint hook never started")
	}
	close(lintRelease)
	wg.Wait()

	events, err := inner.Events(only.ID)
	require.NoError(t, err)
	var lintEvents []bead.BeadEvent
	for _, ev := range events {
		if ev.Kind == "bead-quality.lint" {
			lintEvents = append(lintEvents, ev)
		}
	}
	assert.Equal(t, 1, len(lintEvents),
		"exactly one bead-quality.lint event must be appended; concurrent workers must not duplicate it")
}

// TestPreClaimIntakeRewriteRequiresOwnedReservation is AC #3:
// With actionable_but_rewritten intake, only the claiming worker applies
// description/acceptance rewrites. Concurrent losers cannot double-rewrite
// or append conflicting events because they never reach applyPreClaimIntakeRewrite.
func TestPreClaimIntakeRewriteRequiresOwnedReservation(t *testing.T) {
	inner := bead.NewStore(t.TempDir())
	require.NoError(t, inner.Init(context.Background()))

	original := &bead.Bead{
		ID:          "ddx-rewrite-concurrent",
		Title:       "rewrite ownership",
		Priority:    0,
		Description: "PROBLEM\noriginal problem\n\nROOT CAUSE\noriginal cause\n\nPROPOSED FIX\noriginal fix\n",
		Acceptance:  "1. original criterion\n2. name the test",
	}
	require.NoError(t, inner.Create(context.Background(), original))

	var rewriteCalls atomic.Int32
	rewriteStarted := make(chan struct{}, 1)
	rewriteRelease := make(chan struct{})

	makeRuntime := func(assignee string) (config.ResolvedConfig, ExecuteBeadLoopRuntime) {
		opts := config.TestLoopConfigOpts{Assignee: assignee}
		rcfg := config.NewTestConfigForLoop(opts).Resolve(config.TestLoopOverrides(opts))
		rt := ExecuteBeadLoopRuntime{
			Once: true,
			PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
				rewriteCalls.Add(1)
				select {
				case rewriteStarted <- struct{}{}:
				default:
				}
				select {
				case <-rewriteRelease:
				case <-ctx.Done():
				}
				return PreClaimIntakeResult{
					Outcome: PreClaimIntakeActionableButRewritten,
					Detail:  "safe refinement",
					Rewrite: PreClaimIntakeRewrite{
						Description:   "PROBLEM\noriginal problem\n\nROOT CAUSE\noriginal cause\n\nPROPOSED FIX\noriginal fix\n\nAdd explicit validation step.",
						Acceptance:    "1. original criterion\n2. name the test\n3. lefthook run pre-commit passes",
						ChangedFields: []string{"description", "acceptance"},
					},
				}, nil
			},
		}

	classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, warning)
	rootMutationError := sawParentBackEdge && isProjectRootMutationRejectedDetail(warning)
	message := fmt.Sprintf("check unavailable: %s (continuing)", warning)
	eventType := "pre_claim_intake.warn"
	policyMode := "warn-only"
	decision := "warn"
	suggestedAction := "check the readiness route or harness configuration and retry"
	if rootMutationError {
		message = fmt.Sprintf("check unavailable for bead %s: %s (error)", candidate.ID, warning)
		eventType = "pre_claim_intake.error"
		policyMode = "error"
		decision = "error"
		suggestedAction = "inspect the parent back-edge and clean the project root before retrying"
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
			Phase:    "readiness",
			BeadID:   candidate.ID,
			Message:  message,
			Harness:  harness,
			Provider: provider,
			Model:    model,
		}))
	}
	eventBody := readinessDecisionBody(
		"pre_claim_intake.system_unready",
		classified.Reason,
		"pre_claim_intake",
		policyMode,
		decision,
		suggestedAction,
		map[string]any{
			"bead_id":       candidate.ID,
			"outcome":       string(PreClaimIntakeError),
			"system_reason": classified.SystemReason,
			"detail":        warning,
		},
	)
	if rootMutationError {
		eventBody["severity"] = "error"
	}
	emit(eventType, eventBody)
	if !rootMutationError && appendPreClaimWarn(candidate.ID, "system_unready", warning, now().UTC()) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
case intakeOutcome == PreClaimIntakeActionableAtomic:
	// pass-through
case intakeOutcome == PreClaimIntakeActionableButRewritten:
	if err := applyPreClaimIntakeRewrite(w.Store, candidate.ID, assignee, intakeResult, now().UTC()); err != nil {
		warning := trimDiagnosticPrefix(err.Error(), "pre-claim intake rewrite")
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "bead readiness: rewrite error: %s (continuing with original %s)\n", warning, candidate.ID)
		}
		emit("pre_claim_intake.warn", readinessDecisionBody(
			"pre_claim_intake.rewrite_rejected",
			"rewrite_rejected",
			"pre_claim_intake",
			"warn-only",
			"warn",
			"revise the rewrite so it preserves every explicit commitment",
			map[string]any{
				"bead_id": candidate.ID,
				"outcome": string(PreClaimIntakeActionableButRewritten),
				"detail":  warning,
			},
		))
		if appendPreClaimWarn(candidate.ID, "rewrite_rejected", warning, now().UTC()) {
			return executeBeadIterationOutcome{Stop: true}, nil
		}
	}
case intakeOutcome == PreClaimIntakeError:
	warning := trimDiagnosticPrefix(intakeResult.Detail, "pre-claim intake")
	if warning == "" {
		warning = "readiness check returned intake_error"
	}
	reason := intakeResult.Reason
	systemReason := intakeResult.SystemReason
	if reason == "" && systemReason == "" {
		classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, warning)
		reason = classified.Reason
		systemReason = classified.SystemReason
	}
	rootMutationError := sawParentBackEdge && isProjectRootMutationRejectedDetail(warning)
	message := fmt.Sprintf("check unavailable: %s (continuing)", warning)
	eventType := "pre_claim_intake.warn"
	policyMode := "warn-only"
	decision := "warn"
	suggestedAction := "check the readiness route or harness configuration and retry"
	if rootMutationError {
		message = fmt.Sprintf("check unavailable for bead %s: %s (error)", candidate.ID, warning)
		eventType = "pre_claim_intake.error"
		policyMode = "error"
		decision = "error"
		suggestedAction = "inspect the parent back-edge and clean the project root before retrying"
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
			Phase:    "readiness",
			BeadID:   candidate.ID,
			Message:  message,
			Harness:  harness,
			Provider: provider,
			Model:    model,
		}))
	}
	eventBody := readinessDecisionBody(
		"pre_claim_intake.system_unready",
		reason,
		"pre_claim_intake",
		policyMode,
		decision,
		suggestedAction,
		map[string]any{
			"bead_id":       candidate.ID,
			"outcome":       string(PreClaimIntakeError),
			"system_reason": systemReason,
			"detail":        warning,
		},
	)
	if rootMutationError {
		eventBody["severity"] = "error"
	}
	emit(eventType, eventBody)
	if !rootMutationError && appendPreClaimWarn(candidate.ID, "system_unready", warning, now().UTC()) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
case intakeOutcome == PreClaimIntakeTooLargeDecomposed:
	// too_large_decomposed should move work forward by splitting before
	// claim. Some intake classifiers only identify the need to split;
	// when no concrete children are attached, ask the orchestrator
	// decomposer for executable child specs and then apply them.
	decomp := intakeResult.Decomposition
	if decomp == nil && runtime.PostAttemptDecompositionHook != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "bead readiness requested decomposition; generating split (%s)\n", candidate.ID)
		}
		var hookErr error
		decomp, hookErr = runtime.PostAttemptDecompositionHook(ctx, candidate.ID)
		if hookErr != nil {
			if err := ctx.Err(); err != nil {
				applyStop(work.StopInput{ContextErr: err})
				return executeBeadIterationOutcome{Stop: true}, err
			}
			warning := fmt.Sprintf("decomposition hook unavailable: %s", hookErr.Error())
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "bead decomposition unavailable: %s (%s); continuing with attempt\n", hookErr.Error(), candidate.ID)

